INSERT INTO BDSUPER.GP_PROYECTOS (
    ID_PROYECTO, COD_PROYECTO, MOD_PROYECTO, MOD_DE_INVERSION,
    VAL_TOTAL_PROYECTO, VALOR_APR_VIGENCIA,
    DESCRIPCION_PROYECTO, OBJETIVO_PROYECTO, JUSTIFICACION,
    RESOLUCION_AEI, NUM_ACTA_AEI, FECHA_APR_AEI, NUM_CONSEJEROS, TMP_RECUPERACION,
    ESTUDIO_MERCADO, EVALUACION_SOCIAL, EVALUACION_FINANCIERA,
    NUM_PERSONAS_REFERENCE, NUM_POBLACION_AFECTADA,
    ESTADO_PROYECTO, USUARIO_CREACION, USUARIO_MODIFICACION
) VALUES (
    'ccf04404-0002-8000-8000-000000000001', 'CCF044-04-00028', 2, 4,
    3000000000, 3000000000,
    'Crédito es un programa social en COMFAMILIAR RISARALDA. El presente proyecto, para seguimiento y control posterior de la Supersubsidio, consiste en ampliar el fondo de crédito para el presente año 2025 por un valor de $26.000,0 millones con una aprobación inicial de $18.500,0 millones, y un adición de fondos por Valor de $4.500, 0 millones. en el mes de junio y otra adición de $3.000, 0 millones en el mes de noviembre según última resolución AEI 0009 del 27 de noviembre de 2025.', 'Ampliar los Fondos de Crédito Social en 3.000,0 millones de pesos, para disponer de una mayor capacidad de recursos para los meses de noviembre y diciembre de la vigencia 2025 y así incrementar la operación logrando la satisfacción de los afiliados beneficiarios de la categoría A y B que a cierre de Octubre 30 de 2025; han accedido el 96,51% de esta población. - Otorgar 400 nuevos créditos a beneficiarios a las tasas vigentes. - Facilitar el acceso a servicios financieros a beneficiarios con estrategias de inclusión. -Escalar en cobertura, disponibilidad de recursos y peso específico de Crédito Social en la generación de ingresos. -Contribuir a la bancarización y combatir la alta exclusión del crédito a beneficiarios mediante supresión de barreras de entrada.', 'Otros referentes de justificación de Crédito Social La Caja sobrepasa el 90% de créditos a beneficiarios, logrando alto impacto social, mayor bienestar de los afiliados e incremento de cobertura, montos disponibles por usuario y modalidades. -El crédito a menores tasas y sin barreras son iniciativas socialmente convenientes porque ayudan a sobrellevar las cargas económicas a beneficiarios. -El libre acceso al crédito, la bancarización, las recomendaciones de organismos multilaterales, la experiencia en Banca de pobres, negocios en la base de la pirámide y ser una prioridad de la Ley 21 de 1982, hacen de crédito una excelente inversión social. -El proyecto capitaliza experiencia propia. Esto es útil porque implica liberar beneficiarios del azote de la usura.El servicio está alineado con directrices nacionales y locales de los planes de desarrollo. Es así que el Plan Nacional de Desarrollo 2022-2026 (PND 2022-2026) potencia mundial de la vida Colombia, y dentro de las grandes transformaciones y sus principales metas para el ítem 2 de “Seguridad Humana y Justicia Social” en el numeral ocho sostenibilidad y crecimiento empresarial dentro del literal e en Iniciativas productivas, acceso al financiamiento amplio y educación financiera para avanzar en la democratización del crédito, comenzando por una buena educación financiera, y ofreciéndole a los beneficiarios información adecuada.',
    1, 9, '20251127', 1, 1,
    'Las cajas de compensación en Colombia han sido clave en el bienestar financiero de los afiliados, ofreciendo productos crediticios accesibles. No obstante, entidades como Compensar, Colsubsidio y Cafam han implementado motores de decisiones y créditos cupo rotativo, optimizando la aprobación de créditos y mejorando la inclusión financiera. (; Santiago Etchegoyen, 2024, lunes 7 de octubre). Teniendo en cuenta todos los datos recopilados, se puede evidenciar que con la ampliación de los fondos de crédito, posiblemente impactaríamos un porcentaje alto en la población afiliada del 95%, debido a todo este análisis el mercado potencial para crédito se concentra en personas entre 30 y 49 años, mayormente solteras o en unión libre, pertenecientes a las categorías A y B, con mayor representación en Pereira (62.6%) y Dosquebradas (21.5%). Por otro lado, se observa que hay un declive en la cobertura como en participación entre 2024 y 2025, (de 41,69% a 35,74%). Por otro lado, la categoría B mantiene un comportamiento más estable, con coberturas similares y un crecimiento moderado en desembolsos, aportando el 23% del total, lo que indica una base menos volátil y más constante. En conjunto, el portafolio evidencia una alta concentración en la categoría A, pero con señales de desplazamiento hacia B en 2025, lo que podría reflejar cambios en perfil de riesgo, capacidad de pago o políticas de originación.', 'Impacto social El proyecto presenta dos situaciones con relación a su impacto social. De una parte, el programa, tal como se tiene estructurado actualmente, logra utilidades netas y su cartera es sana, derivadas de las diferentes tasas de colocación a usuarios beneficiarios y tasas superiores cobradas a usuarios de categorías C y particulares, lo que configura una forma de subsidio cruzado a partir de tasas diferenciales entre categorías, de acuerdo a los niveles salariales de los beneficiarios atendidos. En general, dado el propósito misional de COMFAMILIAR RISARALDA, el impacto social es evidente, aún con distinta intensidad sin importar la modalidad de crédito, sobre todo para usuarios beneficiarios, en el sentido de ser créditos de naturaleza social, en todo caso a menores tasas de interés que las cobradas por el sistema financiero tradicional y el mercado extra bancario o de usura. En este sentido COMFAMILIAR RISARALDA establecerá un sistema de control y seguimiento de las siguientes variables: -Monitoreo permanente a la cobertura a beneficiarios y comportamiento de las tasas de interés, de tal forma que se logre garantizar un comportamiento menor de la tasa con relación a los intereses bancarios de mercado para usuarios beneficiarios, sin importar la línea. -Verificación permanente de las variables criticas predefinidas, como el acceso de beneficiarios en mayor proporción a otras categorías (artículo 72 decreto 341 de 1988 y decreto 1053 de 2014)', 'En el flujo de caja del proyecto puro se tuvieron en cuenta los ingresos, egresos, inversiones y depreciaciones por los próximos 7 años.Finalmente se agregó un 5% sobre el valor retornado (interés más capital) como costo administrativo incremental, lográndose de esta forma una TIR del proyecto a una tasa de oportunidad del 8% y que corresponde al 11,5%, lo que indica la conveniencia del proyecto. Nota: El valor de la TIR es cambiante, de conformidad con los cambios de condiciones simuladas en monto, plazo y tasa, de acuerdo al modelo. Criterio de decisión (Indicadores de Evaluación Económica) El proyecto debe adelantarse por tener una tasa interna de retorno mínima (11,3%) superior al costo de oportunidad señalado para este proyecto en el 8,0%. Adicionalmente el proyecto es una iniciativa social que libera del flagelo de la usura por el mercado extra-bancario al que incurren los afiliados y prácticamente, el programa de la Caja operaría con la misma estructura de personal.',
    229495, 7469,
    'BORRADOR', 'SEED_XML', 'SEED_XML'
);

